import axios from 'axios';
import { buildApiUrl } from './api';

// âś… ALWAYS use /api prefix to match Flask
const ROOM_BOOKING_ENDPOINTS = [
  buildApiUrl('/api/room_bookings'),
];

const FOOD_ORDER_ENDPOINTS = [
  buildApiUrl('/api/food_orders'),
];

const STAY_BOOKING_ENDPOINTS = [
  buildApiUrl('/api/stay_bookings'),
];

const postCheckoutData = async (endpoints, payload) => {
  let lastError = null;

  for (const endpoint of endpoints) {
    try {
     return await axios.post(endpoint, payload, {
  timeout: 10000,
  withCredentials: true,   // âś… THIS IS THE FIX
  headers: {
    'Content-Type': 'application/json',
  },
});
    } catch (error) {
      console.error("API ERROR:", endpoint, error.response?.data || error.message);
      lastError = error;
    }
  }

  throw lastError;
};

export const submitRoomBooking = (payload) =>
  postCheckoutData(ROOM_BOOKING_ENDPOINTS, payload);

export const submitFoodOrder = (payload) =>
  postCheckoutData(FOOD_ORDER_ENDPOINTS, payload);

export const submitStayBooking = (payload) =>
  postCheckoutData(STAY_BOOKING_ENDPOINTS, payload);
